; font-size:clamp(22px,4.5vw,36px); direction:ltr; text-align:left; }\n  .cta-btn { display:inline-block; background:{{brand_primary_color}}; color:#fff; font-weight:800; font-size:clamp(11px,1.8vw,16px); padding:8px 18px; border-radius:4px; }\n  .contact-left { display:flex; align-items:center; gap:12px; }\n  .logo-in-bar img { height:clamp(30px,6vw,48px); filter:drop-shadow(0 3px 10px rgba(0,0,0,0.9)); object-fit:contain; }\n  .biz-name { color:#fff; font-weight:800; font-size:clamp(13px,2.2vw,18px); }\n  .info-line { color:rgba(255,255,255,0.5); font-size:clamp(8px,1.2vw,10px); }\n  .kashrut-in-bar img { height:clamp(20px,3.5vw,30px); opacity:0.6; filter:brightness(0) invert(1); }\n  .extra-row { position:absolute; bottom:60px; width:100%; z-index:10; padding:0 7%; display:flex; gap:8px; justify-content:flex-end; }\n  .extra-chip { color:rgba(255,255,255,0.5); font-size:clamp(7px,1.1vw,9px); background:rgba(0,0,0,0.5); padding:2px 8px; border-radius:2px; }\n</style>\n<div class="ad">\n  <img src="{{image_url}}" class="bg-img" alt="bg">\n  <div class="grad-bottom"></div>\n  {{#if promo_text}}<div class="promo-badge">{{promo_text}}</div>{{/if}}\n  <div class="bottom-zone">\n    {{#if headline}}<h1 class="headline">{{headline}}</h1>{{/if}}\n    {{#if subheadline}}<div class="sub-strip">{{subheadline}}</div>{{/if}}\n  </div>\n  {{#if branches}}<div class="extra-row">{{#each branches}}<span class="extra-chip">📍 {{this}}</span>{{/each}}</div>{{/if}}\n  {{#unless branches}}{{#if address_list}}<div class="extra-row">{{#each address_list}}<span class="extra-chip">📍 {{this}}</span>{{/each}}</div>{{/if}}{{/unless}}\n  <div class="contact-bar">\n    <div class="contact-right">\n      <div class="phone-block">\n        {{#if phone}}<div class="phone-label">לפרטים:</div><div class="phone-num">{{phone}}</div>{{/if}}\n      </div>\n      {{#if ctaText}}<div class="cta-btn">{{ctaText}}</div>{{/if}}\n    </div>\n    <div class="contact-left">\n      {{#if kashrut_logo}}<div class=